+    impl BlockingGate {
+        fn wait_until_entered(&self) {
+            let (lock, cvar) = &*self.state;
+            let mut state = lock.lock().expect("gate lock poisoned");
+            while !state.entered {
+                state = cvar.wait(state).expect("gate wait poisoned");
+            }
+        }
+
+        fn release(&self) {
+            let (lock, cvar) = &*self.state;
+            let mut state = lock.lock().expect("gate lock poisoned");
+            state.release = true;
+            cvar.notify_all();
+        }
+
+        fn block_here(&self) {
+            let (lock, cvar) = &*self.state;
+            let mut state = lock.lock().expect("gate lock poisoned");
+            state.entered = true;
+            cvar.notify_all();
+            while !state.release {
+                state = cvar.wait(state).expect("gate wait poisoned");
+            }
+        }
+    }
